    { title: "Travel Vlog", author: "World Wonders", views: "300K", date: "1 day ago", thumbnail: "https://via.placeholder.com/300x170?text=Travel", youtubeId: "dQw4w9WgXcQ" }
];

const videoGrid = document.getElementById('videoGrid');
const modal = document.getElementById('videoModal');
const videoPlayer = document.getElementById('videoPlayer');
const closeBtn = document.querySelector('.close-btn');

// Function to render video cards
function renderVideos() {
    videoGrid.innerHTML = videos.map(video => `
        <div class="video-card" onclick="openVideo('${video.youtubeId}')">
            <img src="${video.thumbnail}" alt="${video.title}" class="thumbnail">
            <div class="card-info">
                <h3>${video.title}</h3>
                <p>${video.author}</p>
                <p>${video.views} views • ${video.date}</p>
            </div>
        </div>
    `).join('');
}

// Open Modal and Load Video
function openVideo(id) {
    // In a real app, construct the full embed URL based on the ID
    const embedUrl = `https://www.youtube.com/embed/${id}`;
    videoPlayer.src = embedUrl;
    modal.style.display = 'flex';
}

// Close Modal
closeBtn.onclick = () => {
    modal.style.display = 'none';
    videoPlayer.src = ''; // Stop video playback
};

window.onclick = (event) => {
    if (event.target == modal) {
        modal.style.display = 'none';
        videoPlayer.src = '';
    }
}

// Initialize
renderVideos();
```

